import { arrayify } from '@ethersproject/bytes'
import {
    ConfirmOptions,
    Connection,
    GetVersionedTransactionConfig,
    ParsedTransactionWithMeta,
    PublicKey,
    SendOptions,
    TransactionSignature,
    sendAndConfirmRawTransaction,
} from '@solana/web3.js'

import {
    Block,
    BlockTag,
    BlockWithTransactions,
    Finality,
    Provider,
    SignedTransaction,
    TransactionPending,
    TransactionReceipt,
    TransactionResponse,
} from '@layerzerolabs/lz-core'

export class SolanaProvider implements Provider {
    nativeProvider: Connection

    constructor(public url: string) {
        this.nativeProvider = new Connection(url, 'confirmed')
    }

    static from(url: string): SolanaProvider

    static from(source: string): SolanaProvider {
        if (typeof source === 'string') {
            return new SolanaProvider(source)
        } else {
            throw new Error('Invalid parameters')
        }
    }

    get native(): unknown {
        return this.nativeProvider
    }

    async getBalance(address: string): Promise<string> {
        return this.nativeProvider.getBalance(new PublicKey(address)).then((balance) => balance.toString())
    }

    async getBlock(slot: string | number): Promise<Block> {
        const response = await this.nativeProvider.getParsedBlock(parseInt(slot.toString()), {
            commitment: 'confirmed',
        })
        return Block.from(response)
    }

    async getBlockNumber(): Promise<number> {
        return this.nativeProvider.getBlockHeight({ commitment: 'confirmed' })
    }

    async getSlot(finality?: Finality): Promise<number> {
        return this.nativeProvider.getSlot(finality)
    }

    async getBlockTimestamp(slot: string | number): Promise<number> {
        const t = await this.nativeProvider.getBlockTime(parseInt(slot.toString()))
        if (t === null) {
            throw new Error('Block timestamp not available')
        }
        return t
    }

    /**
     *
     * @param txHash string The transaction hash is TransactionSignature in Solana
     * @returns TransactionResponse
     */
    async getTransaction(txHash: string): Promise<TransactionResponse> {
        const response: ParsedTransactionWithMeta | null = await this.nativeProvider.getParsedTransaction(txHash, {
            commitment: 'confirmed',
        })
        return TransactionResponse.from(response)
    }

    async getTransactionReceipt(txHash: string): Promise<TransactionReceipt> {
        const response: ParsedTransactionWithMeta | null = await this.nativeProvider.getParsedTransaction(txHash, {
            commitment: 'confirmed',
        } satisfies GetVersionedTransactionConfig)
        if (response === null) {
            throw new Error('Transaction not found')
        }
        return TransactionReceipt.from(response)
    }

    // eslint-disable-next-line @typescript-eslint/require-await
    async getTransactionCount(
        _addressOrName: string | Promise<string>,
        _blockTag?: BlockTag | Promise<BlockTag>
    ): Promise<number> {
        await Promise.resolve()
        throw new Error('Method not implemented.')
    }

    async getBlockWithTransactions(blockTag: string | number): Promise<BlockWithTransactions> {
        if (typeof blockTag === 'string') {
            blockTag = parseInt(blockTag)
        }
        const response = await this.nativeProvider.getBlock(blockTag, { transactionDetails: 'full' })
        if (response === null) {
            throw new Error('Block not found')
        }
        return BlockWithTransactions.from(response)
    }

    async sendTransaction(transaction: SignedTransaction, sendOptions?: SendOptions): Promise<TransactionPending> {
        const _transaction = transaction.signed as string

        const response = await this.nativeProvider.sendRawTransaction(Buffer.from(arrayify(_transaction)), sendOptions)
        return TransactionPending.from(response)
    }

    async sendAndConfirm(transaction: SignedTransaction, opts?: ConfirmOptions): Promise<TransactionReceipt> {
        const _transaction = transaction.signed as string
        const response: TransactionSignature = await sendAndConfirmRawTransaction(
            this.nativeProvider,
            Buffer.from(arrayify(_transaction)),
            opts
        )
        return TransactionReceipt.from(response)
    }
}
