import { hexlify } from '@ethersproject/bytes'
import { getPublicKey, sign } from '@noble/secp256k1'

export { recoverPublicKey } from '@noble/secp256k1'

export async function signWithECDSA(
    data: Buffer,
    privateKey: string
): Promise<{ signature: Uint8Array; recoveryId: number }> {
    const [signature, recoveryId] = await sign(data, privateKey.replace('0x', ''), {
        canonical: true,
        recovered: true,
        der: false,
    })
    return {
        signature,
        recoveryId,
    }
}

export function getECDSAPublicKey(privateKey: string): string {
    // remove the compression byte
    return hexlify(getPublicKey(privateKey.replace('0x', '')).subarray(1))
}
